import React from 'react'
import AboutStack from '../components/aboutMe_Stack'
import Choose from '../components/chooseComponent'
import Website from '../components/websites'
import Contactme from '../components/contactMe'
import Softwares from '../components/softwares'


class Home extends React.Component {
    state = {
        component: 'Website'
    }
    render() {
        const website = () => {
            this.setState({ component: 'Website' })
        }
        const softwares = () => {
            this.setState({ component: 'Softwares' })
        }
        const moveMouse = () => {
            console.log('clicked')
        }
        const color = {
            color: 'white',
            margin: "10px",
            maxWidth: "600px",
        }
        return (
            <div>
                <div className="banner">
                    <div className="profileImage">
                        <img src="/img/nigeria1.png" />
                    </div>
                    <div style={color} >
                        <h1 className="name"> Hi, I am <span>Jonathan Atiene </span></h1>
                        <h3 className="title">A professional Web Developer</h3>
                        <p>
                            I love Coding
                            <li> Language: javascript, Ruby </li>
                            <li> DataBase: MongoDB, Pg, FireStore 😉</li>
                            <li> Web Frameworks: Ruby on Rails, React, Vue js, Angular, Node js, WordPress </li>
                            <li> Education: Andela Google Africa, Progate, The Odin Project </li>
                            <li></li>

                        </p>
                        <a href="tel:+2348141838266"> <button className="contactme-button">Hire Me</button>  </a>
                    </div>
                </div>
                <div align="center" id="about">
                    <img src="./img/mouse.svg" className="mouse" onClick={moveMouse} /> </div>
                <div className="container">
                    <AboutStack />
                    <hr />
                </div>

                <div className="container" >
                    <Choose softwares={softwares} website={website} state={this.state} />
                </div>

                <div>
                    {
                        this.state.component === 'Website' ?
                            <Website /> : <Softwares />
                    }
                </div>

                <div id="contact">
                    <Contactme />
                </div>

                <footer>
                    <section className="container">
                        <div> All rights reserved - Jonathan-{new Date().getFullYear()} </div>
                        <div> Designed By : akaraonye.stephen@gmail.com </div>
                        <div> Developed By - B. Jonathan </div>
                    </section>

                </footer>
            </div>
        )
    }
}

export default Home