import React from 'react'

const Website = function () {
    const projects = [ { name: '2DOTS PROPERTIES ', image: '/img/2dots.png', link:'https://2dotsproperties.com/' },{ name: 'BOT FORM ', image: '/img/bot.png', link:'https://2dotsproperties.com/' } , { name: 'DOGGYGRAM ', image: '/img/DoggyGram.png', link:'#' }]
    const projectMap = projects.map((e, i) => {
        return(
            <div style={{border:'1px solid #D9D9D9', maxWidth:'374px', maxHeight:'500px', position:'relative'}} key={i}>
                <div className="siteImage">
                    <img src={e.image} />
                </div>
                <div className="siteName">
                    <a href={e.link} target="_blank">{e.name}</a> 
                </div>
            </div> 
        )
    })
    return ( 
        <div className = "websites container" >
            {projectMap}
        </div>
    )
}

export default Website