import React from 'react'
import axios from "axios"
class Contactme extends React.Component {

    state = {
        name: '',
        message: '',
        from: ''
    }
    render() {
        const submitMe = (e) => {
            e.preventDefault()
            e.persist()
            var name = e.target.First_Name.value + " | " + e.target.email.value
            var from = e.target.email.value
            var message = e.target.message.value

            var message = {
                name,
                message,
                from
            }
            axios.post("https://my-form-mail.herokuapp.com/mail", message).then(res => {
                // alert(res.data.message)
                e.target.First_Name.value = " "
                e.target.email.value = " "
                e.target.message.value = " "
            }, err => {
                // alert('error')
                e.target.First_Name.value = " "
                e.target.email.value = " "
                e.target.message.value = " "
            })



        }
        return (
            <div className="Contactme">
                <div className="container formflex">
                    <form onSubmit={submitMe}>
                        <div>
                            <h1> Send a message </h1>
                            <p>

                            </p>
                        </div>
                        <div className="formflex">
                            <input className="input" name="First_Name" placeholder=" First Name " />
                            <input className="input" name="Second_Name" placeholder=" Second Name " />
                        </div>
                        <div>
                            <input type="email" className="input" name="email" placeholder=" Email address " />
                        </div>

                        <div>
                            <textarea placeholder="Project Details" name="message">

                            </textarea>
                        </div>

                        <div>
                            <button className="contactme-button default active"> SEND MESSAGE </button>
                        </div>
                    </form>
                    <div className="footerImages">
                        <p><a href="https://twitter.com/bemijonathan"> Twitter </a>  </p>
                        <p><a href="https://www.facebook.com/jonathan.atiene" > Facebook </a></p>
                        <p><a href="https://www.instagram.com/bemijonathan/"> Instagram </a>  </p>
                    </div>

                </div>
            </div>
        )
    }
}

export default Contactme