import React from 'react'
import {NavLink} from 'react-router-dom'
import {connect} from 'react-redux'
import {toggleModal} from'../store/actions/toggleModal'


class Nav extends React.Component{

    navbar = 'navbar'
    state={
        background:'black'
    }
   
    render(){
        const displayMe = () => {
            this.props.displayMe()
        }
        return(
            <div>
                <nav className={this.navbar} style={{background:this.state.background}}>
                <div className="mobileNav"> 
                    <img src="/img/nav.svg" onClick={ displayMe }/>
                </div>
                    <ul className="container">
                        <li> <a href='/#about'> About me </a></li>
                        <li> <a href='/#contact'> Contact me </a> </li>
                        <li> <a href='/#project'> Projects </a> </li>
                        {/* <li> <NavLink to='/#blog'> Blog </NavLink> </li> */}
                    </ul>
                </nav>
            </div>
        )
    }
}

const mapActionstoState = (dispatch) => {
    return{
        displayMe: () => dispatch(toggleModal())
    }
}

export default connect(null, mapActionstoState)(Nav)