import React from 'react'
import { connect } from 'react-redux'
import { toggleModal } from "../store/actions/toggleModal";
function modal(props) {
    const clicked = () => {
        props.clicked()
    }
    return (
        <div className="modal">
            <li onClick={clicked}>
                about
            </li>
            <li onClick={clicked}>
                blog
            </li>
            <li onClick={clicked}>
                contact
            </li>
            <li onClick={clicked}>
                projects
            </li>
        </div>
    )
}

const mappropstostate = (dispatch) => {
    return {
        clicked: () => dispatch(toggleModal())
    }
}
export default connect(null, mappropstostate)(modal)